+/**
+ * Sanitize SVG content to prevent XSS attacks.
+ * Removes dangerous elements and attributes from SVG strings.
+ */
+
+/**
+ * List of SVG elements that could be used for XSS.
+ */
+const DANGEROUS_ELEMENTS = [
+    'script',
+    'animate',
+    'set',
+    'animateMotion',
+    'animateTransform',
+    'animateColor',
+    'handler',
+    'listener'
+];
+
+/**
+ * List of attribute prefixes/names that could be used for XSS.
+ */
+const DANGEROUS_ATTRIBUTES = [
+    'onload',
+    'onclick',
+    'onmouseover',
+    'onmouseout',
+    'onmousemove',
+    'onfocus',
+    'onblur',
+    'onerror',
+    'onabort',
+    'onactivate',
+    'onbegin',
+    'onend',
+    'onrepeat',
+    'onresize',
+    'onscroll',
+    'onunload',
+    'onzoom',
+    'xlink:href',
+    'href'
+];
+
+/**
+ * Dangerous URI schemes that can execute scripts.
+ */
+const DANGEROUS_URI_SCHEMES = /^\s*(javascript|vbscript|data):/i;
+
+/**
+ * Remove dangerous elements and attributes from an SVG DOM element recursively.
+ * @param {Element} element - The SVG DOM element to sanitize.
+ */
+const sanitizeElement = function (element) {
+    // Remove dangerous child elements
+    const children = Array.from(element.childNodes);
+    for (const child of children) {
+        if (child.nodeType === child.ELEMENT_NODE) {
+            const tagName = child.tagName && child.tagName.toLowerCase().replace(/^svg:/, '');
+            if (DANGEROUS_ELEMENTS.indexOf(tagName) !== -1) {
+                element.removeChild(child);
+                continue;
+            }
+            sanitizeElement(child);
+        }
+    }
+
+    // Remove dangerous attributes from this element
+    if (element.attributes) {
+        const attrs = Array.from(element.attributes);
+        for (const attr of attrs) {
+            const attrName = attr.name.toLowerCase();
+            // Remove event handler attributes
+            if (attrName.startsWith('on') || DANGEROUS_ATTRIBUTES.indexOf(attrName) !== -1) {
+                // For href/xlink:href, allow only safe URIs
+                if ((attrName === 'href' || attrName === 'xlink:href')) {
+                    if (DANGEROUS_URI_SCHEMES.test(attr.value)) {
+                        element.removeAttribute(attr.name);
+                    }
+                } else {
+                    element.removeAttribute(attr.name);
+                }
+            }
+        }
+    }
+};
+
+/**
+ * Sanitize an SVG string to remove XSS vectors.
+ * @param {string} svgString - The SVG string to sanitize.
+ * @returns {string} - The sanitized SVG string.
+ */
+const sanitize = function (svgString) {
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(svgString, 'image/svg+xml');
+    const svgElement = doc.documentElement;
+
+    // Check for parse errors
+    if (svgElement.tagName === 'parsererror' ||
+        svgElement.querySelector('parsererror')) {
+        // Return empty SVG on parse error
+        return '<svg xmlns="http://www.w3.org/2000/svg"></svg>';
+    }
+
+    sanitizeElement(svgElement);
+
+    return new XMLSerializer().serializeToString(svgElement);
+};
+
+module.exports = {sanitize};

